// Build the prompt payload for Claude
const payload = $input.all()[0].json;
const webhook = $('HeyReach Webhook').first().json.body;
const thread = payload.messages || [];

const formattedThread = thread.map(m => ({
  sender: m.isOurs ? 'us' : 'them',
  text: m.text,
  timestamp: m.createdAt
}));

return [{
  json: {
    conversationId: webhook.conversationId,
    senderId: webhook.linkedInAccountId,
    leadProfile: {
      name: webhook.leadName || 'Unknown',
      role: webhook.leadTitle || '',
      company: webhook.leadCompany || '',
      linkedInUrl: webhook.leadLinkedInUrl
    },
    thread: formattedThread,
    rawWebhook: webhook
  }
}];

