// Parse Claude's routing decision
const response = $input.first().json;
const text = response.content[0].text;

let decision;
try {
  const clean = text.replace(/```json\n?|\n?```/g, '').trim();
  decision = JSON.parse(clean);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  decision = match ? JSON.parse(match[0]) : { routing_decision: 'human_takeover', reason: 'parse_error' };
}

const upstream = $('Prepare Claude Input').first().json;

return [{ json: { ...upstream, decision } }];

